examples.code:
airfield RAF_Maintenance_Base {
  aircraft F35_Lightning {
    wingspan 10.7m
    length 15.6m
    height 4.4m
    tailHeight 4.4m
  }

  aircraft Hawk_T2 {
    wingspan 9.9m
    length 12.4m
    height 4.0m
    tailHeight 4.0m
  }

  hangar FighterMaintenanceHangar {
    doorWidth 25.0m
    doorHeight 8.0m
    grid baygrid {
      bay FM_Bay1 {
        width 20.0m
        depth 25.0m
        height 8.0m
        adjacent { FM_Bay2 }
      }
      bay FM_Bay2 {
        width 20.0m
        depth 25.0m
        height 8.0m
        adjacent { FM_Bay1 }
      }
    }
  }

  induct F35_Lightning into FM_Bay1 from 2025-12-11T07:00 to 2025-12-11T15:00;

  auto-induct Hawk_T2 duration 180 minutes prefer FighterMaintenanceHangar;
}
